package main

import (
    "fmt"
    "errors"
)

// ---- Student struct ----
type Student struct {
    ID     int
    Name   string
    Age    int
    Grade  float64
}

// ---- Custom errors ----
type StudentNotFoundError struct {
    ID int
}

func (e StudentNotFoundError) Error() string {
    return fmt.Sprintf("student with ID %d not found", e.ID)
}

type StudentAlreadyExistsError struct {
    ID int
}

func (e StudentAlreadyExistsError) Error() string {
    return fmt.Sprintf("student with ID %d already exists", e.ID)
}

// ---- Student record system ----
type StudentSystem struct {
    students map[int]Student
}

func NewStudentSystem() *StudentSystem {
    return &StudentSystem{
        students: make(map[int]Student),
    }
}

func (s *StudentSystem) Add(student Student) error {
    if _, exists := s.students[student.ID]; exists {
        return StudentAlreadyExistsError{ID: student.ID}
    }
    s.students[student.ID] = student
    return nil
}

func (s *StudentSystem) Get(id int) (Student, error) {
    if student, exists := s.students[id]; exists {
        return student, nil
    }
    return Student{}, StudentNotFoundError{ID: id}
}

func (s *StudentSystem) Update(student Student) error {
    if _, exists := s.students[student.ID]; !exists {
        return StudentNotFoundError{ID: student.ID}
    }
    s.students[student.ID] = student
    return nil
}

func (s *StudentSystem) Delete(id int) error {
    if _, exists := s.students[id]; !exists {
        return StudentNotFoundError{ID: id}
    }
    delete(s.students, id)
    return nil
}

func (s *StudentSystem) List() []Student {
    students := make([]Student, 0, len(s.students))
    for _, student := range s.students {
        students = append(students, student)
    }
    return students
}

func (s *StudentSystem) FindByName(name string) []Student {
    result := []Student{}
    for _, student := range s.students {
        if student.Name == name {
            result = append(result, student)
        }
    }
    return result
}

func main() {
    system := NewStudentSystem()

    // ---- Add students ----
    fmt.Println("=== Adding Students ===")

    students := []Student{
        {ID: 1, Name: "Hero", Age: 20, Grade: 3.75},
        {ID: 2, Name: "Aragorn", Age: 22, Grade: 3.50},
        {ID: 3, Name: "Gandalf", Age: 21, Grade: 3.90},
    }

    for _, s := range students {
        err := system.Add(s)
        if err != nil {
            fmt.Println("Error:", err)
        } else {
            fmt.Printf("Added: %s (ID: %d)\n", s.Name, s.ID)
        }
    }

    // ---- Try to add duplicate ----
    err := system.Add(Student{ID: 1, Name: "Duplicate", Age: 20, Grade: 3.0})
    if err != nil {
        fmt.Println("Error:", err)
    }

    // ---- Get student ----
    fmt.Println("\n=== Getting Student ===")
    student, err := system.Get(1)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Printf("Found: %s (ID: %d, Age: %d, Grade: %.2f)\n",
            student.Name, student.ID, student.Age, student.Grade)
    }

    // ---- Get non-existent ----
    _, err = system.Get(99)
    if err != nil {
        fmt.Println("Error:", err)
    }

    // ---- Update student ----
    fmt.Println("\n=== Updating Student ===")
    student.Grade = 3.85
    err = system.Update(student)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Printf("Updated: %s (Grade: %.2f)\n", student.Name, student.Grade)
    }

    // ---- List all students ----
    fmt.Println("\n=== All Students ===")
    for _, s := range system.List() {
        fmt.Printf("ID: %d, Name: %s, Age: %d, Grade: %.2f\n",
            s.ID, s.Name, s.Age, s.Grade)
    }

    // ---- Delete student ----
    fmt.Println("\n=== Deleting Student ===")
    err = system.Delete(2)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Deleted student with ID 2")
    }

    // ---- List after deletion ----
    fmt.Println("\n=== After Deletion ===")
    for _, s := range system.List() {
        fmt.Printf("ID: %d, Name: %s\n", s.ID, s.Name)
    }
}

