package main

import (
    "fmt"
    "errors"
)

type Product struct {
    ID    int
    Name  string
    Price float64
}

type ProductNotFoundError struct {
    ID int
}

func (e ProductNotFoundError) Error() string {
    return fmt.Sprintf("product with ID %d not found", e.ID)
}

type ProductStore struct {
    products map[int]Product
}

func NewProductStore() *ProductStore {
    return &ProductStore{products: make(map[int]Product)}
}

func (p *ProductStore) Add(product Product) error {
    if _, exists := p.products[product.ID]; exists {
        return fmt.Errorf("product with ID %d already exists", product.ID)
    }
    p.products[product.ID] = product
    return nil
}

func (p *ProductStore) Get(id int) (Product, error) {
    if product, exists := p.products[id]; exists {
        return product, nil
    }
    return Product{}, ProductNotFoundError{ID: id}
}

func (p *ProductStore) Delete(id int) error {
    if _, exists := p.products[id]; !exists {
        return ProductNotFoundError{ID: id}
    }
    delete(p.products, id)
    return nil
}

func (p *ProductStore) List() []Product {
    products := []Product{}
    for _, product := range p.products {
        products = append(products, product)
    }
    return products
}

func main() {
    store := NewProductStore()

    store.Add(Product{ID: 1, Name: "Sword", Price: 50.0})
    store.Add(Product{ID: 2, Name: "Shield", Price: 40.0})

    product, err := store.Get(1)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Printf("Product: %+v\n", product)
    }

    err = store.Delete(2)
    if err != nil {
        fmt.Println("Error:", err)
    } else {
        fmt.Println("Deleted product 2")
    }

    fmt.Println("Products:")
    for _, p := range store.List() {
        fmt.Printf("  ID: %d, Name: %s, Price: %.2f\n", p.ID, p.Name, p.Price)
    }
}
